import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Send, Trash2, Loader2, Lightbulb, User, Square } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useMerchantConsultant } from "@/hooks/useMerchantConsultant";
import ReactMarkdown from "react-markdown";

const QUICK_QUESTIONS = [
  "如何提升客流量？",
  "差评处理策略",
  "节日营销方案",
  "如何降低食材成本？",
  "提升复购率的方法",
  "如何设计会员体系？",
];

const MerchantAIConsultant = () => {
  const { t } = useTranslation();
  const [input, setInput] = useState("");
  const scrollAreaRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const {
    messages,
    isLoading,
    isLoadingHistory,
    sendMessage,
    clearChat,
    stopGeneration,
    loadChatHistory,
  } = useMerchantConsultant();

  useEffect(() => {
    loadChatHistory();
  }, [loadChatHistory]);

  useEffect(() => {
    if (scrollAreaRef.current) {
      scrollAreaRef.current.scrollTop = scrollAreaRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    sendMessage(input.trim());
    setInput("");
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  const handleQuickQuestion = (question: string) => {
    sendMessage(question);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] max-w-4xl mx-auto p-4">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-lg bg-amber-100 dark:bg-amber-900/30">
            <Lightbulb className="h-6 w-6 text-amber-600" />
          </div>
          <div>
            <h1 className="text-xl font-bold">营销经营顾问</h1>
            <p className="text-sm text-muted-foreground">专业餐饮零售经营建议</p>
          </div>
        </div>
        <Button variant="outline" size="sm" onClick={clearChat} disabled={messages.length === 0 && !isLoading}>
          <Trash2 className="h-4 w-4 mr-1" />
          清空
        </Button>
      </div>

      {/* Messages */}
      <ScrollArea className="flex-1 border rounded-lg p-4 mb-4" ref={scrollAreaRef}>
        <div className="space-y-4">
          {isLoadingHistory && (
            <div className="text-center py-4">
              <Loader2 className="h-5 w-5 animate-spin mx-auto text-muted-foreground" />
              <p className="text-sm text-muted-foreground mt-2">加载历史记录...</p>
            </div>
          )}

          {!isLoadingHistory && messages.length === 0 && (
            <div className="text-center py-8">
              <Lightbulb className="h-12 w-12 mx-auto mb-4 text-amber-500/50" />
              <p className="text-lg font-medium mb-2">您好！我是您的专属经营顾问</p>
              <p className="text-sm text-muted-foreground mb-6">
                拥有 15 年餐饮零售行业经验，为您提供营销策略、运营诊断、成本控制等专业建议
              </p>
              <div className="flex flex-wrap gap-2 justify-center max-w-lg mx-auto">
                {QUICK_QUESTIONS.map((q) => (
                  <Button
                    key={q}
                    variant="outline"
                    size="sm"
                    onClick={() => handleQuickQuestion(q)}
                    className="text-xs"
                  >
                    {q}
                  </Button>
                ))}
              </div>
            </div>
          )}

          {messages.map((message, index) => (
            <div
              key={index}
              className={`flex gap-3 ${message.role === "user" ? "justify-end" : "justify-start"}`}
            >
              {message.role === "assistant" && (
                <div className="w-8 h-8 rounded-full bg-amber-100 dark:bg-amber-900/30 flex items-center justify-center flex-shrink-0">
                  <Lightbulb className="h-4 w-4 text-amber-600" />
                </div>
              )}
              <div
                className={`max-w-[85%] rounded-lg px-4 py-2 ${
                  message.role === "user"
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted"
                }`}
              >
                {message.role === "assistant" ? (
                  <div className="prose prose-sm dark:prose-invert max-w-none">
                    {message.content ? (
                      <ReactMarkdown>{message.content}</ReactMarkdown>
                    ) : (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    )}
                  </div>
                ) : (
                  <p className="whitespace-pre-wrap">{message.content}</p>
                )}
              </div>
              {message.role === "user" && (
                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                  <User className="h-4 w-4 text-primary" />
                </div>
              )}
            </div>
          ))}
        </div>
      </ScrollArea>

      {/* Input */}
      <form onSubmit={handleSubmit} className="flex gap-2">
        <Textarea
          ref={textareaRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="描述您遇到的经营问题，我来帮您分析..."
          disabled={isLoading}
          className="flex-1 min-h-[44px] max-h-[120px] resize-none"
          rows={1}
        />
        {isLoading ? (
          <Button type="button" variant="outline" size="icon" onClick={stopGeneration}>
            <Square className="h-4 w-4" />
          </Button>
        ) : (
          <Button type="submit" size="icon" disabled={!input.trim()}>
            <Send className="h-4 w-4" />
          </Button>
        )}
      </form>
    </div>
  );
};

export default MerchantAIConsultant;
